import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface ListeningSummary {
  totalHours: number;
  averagePerDay: number;
}

interface Artist {
  name: string;
  hours: number;
}

interface Genre {
  genre: string;
  hours: number;
}

interface MusicData {
  listeningSummary: ListeningSummary;
  topArtists: Artist[];
  topGenres: Genre[];
}

export default function Widget() {
  const musicData = response.data as MusicData;
  const { listeningSummary, topArtists, topGenres } = musicData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1DB954' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFFFFF' }}>
              Music Listening Summary
            </Typography>
            <Typography variant="body2" sx={{ color: '#D1FAE5', mb: 1 }}>
              Total Hours: {listeningSummary.totalHours.toFixed(1)}
            </Typography>
            <Typography variant="body2" sx={{ color: '#D1FAE5' }}>
              Average Per Day: {listeningSummary.averagePerDay.toFixed(1)}
            </Typography>
          </Box>

          <Stack spacing={1.5}>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Top Artists
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {topArtists.map((artist) => (
                <Chip
                  key={artist.name}
                  label={`${artist.name}: ${artist.hours.toFixed(1)}h`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#1ED760', color: '#000000' }}
                />
              ))}
            </Stack>
          </Stack>

          <Box sx={{ width: '100%', height: 150 }}>
            <PieChart
              height={150}
              series={[
                {
                  data: topGenres.map((genre) => ({ id: genre.genre, value: genre.hours })),
                  label: {
                    type: 'donut',
                    text: topGenres.map((g) => g.genre),
                    color: '#FFFFFF',
                    fontSize: 10,
                  },
                  colorPalette: ['#1ED760', '#1DB954', '#1AA34A'],
                },
              ]}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
